import React, { useState } from 'react';
import Select from 'react-select';

const EditLab = ({ labhour, handleUpdate, handleCancel,projects }) => {
  const [editedLabHour, setEditedLabHour] = useState({ ...labhour });

  const handleInputChange = (event) => {
    const { name, value } = event.target;
    setEditedLabHour((prevLabHour) => ({
      ...prevLabHour,
      [name]: value,
    }));
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    handleUpdate(editedLabHour);
    resetForm();
  };

  const resetForm = () => {
    setEditedLabHour({
      // Reset the fields as needed for the Lab
      // Example:
      name: '',
        labid: '',
        start: '',
        end: '',
      // Add other fields here
    });
  };

  return (
    <div className="container">
      <h2 className="heading">Edit Lab</h2>
      <form className="form" onSubmit={handleSubmit}>
        <div className="form-row">
                            <div className="form-group">
                                <label>Project:</label>
                                <Select
                                    name="labid"
                                    value={projects.find(Lab => Lab.prid === labhour.labid) ? { value: labhour.labid, label: projects.find(Lab => Lab.prid === dayRecords.labid).name } : null}
                                    options={projects.map(Lab => ({
                                        value: Lab.prid,
                                        label: Lab.name,
                                    }))}
                                    onChange={selectedOption => handleInputChange('labid', selectedOption.value)}
                                    placeholder="Select a Lab"
                                    required
                                />
                            </div>
                            <div className="form-group">
                                <label htmlFor={`start`}>Start Time (24h format)</label>
                                <input
                                    id={`start`}
                                    type="time"
                                    name="start"
                                    value={labhour.start}
                                    onChange={e => handleInputChange('start', e.target.value)}
                                    placeholder="HH:MM" // Hinting at the expected format
                                    className="form-control"
                                />
                            </div>
                            <div className="form-group">
                                <label htmlFor={`end`}>End Time (24h format)</label>
                                <input
                                    id={`end`}
                                    type="time"
                                    name="end"
                                    value={labhour.end}
                                    onChange={e => handleInputChange('end', e.target.value)}
                                    placeholder="HH:MM" // Hinting at the expected format
                                    className="form-control"
                                />
                            </div>
          <button type="submit">Edit Lab</button>
          <button type="button" className="add_btn" onClick={handleCancel}>
            Cancel
          </button>
        </div>
      </form>

    </div>
  );
};

export default EditLab;
